{"procName":"dbo.tr_dinhmuc_son3_insert","body":"CREATE   PROCEDURE [dbo].[TR_DINHMUC_SON3_INSERT]
(
	@id uniqueidentifier,
	@masp nvarchar(200),
	@stt int,
	@buoc nvarchar(200),
	@mact nvarchar(50),
	@tenct nvarchar(max),
	@soluong float,
	@matson nvarchar(50),
	@t_sort int,
	@ngaytao datetime,
	@nguoitao nvarchar(50),
	@ngaysua datetime,
	@nguoisua nvarchar(50),
	@makhuvuc nvarchar(50) = NULL,
	@macongdoan nvarchar(50) = NULL,
	@stt_buoc nvarchar(5) = NULL,
	@donhot nvarchar(200) = NULL,
	@thoigiankho nvarchar(200) = NULL,
	@cachthuchien nvarchar(max) = NULL,
	@tonghonhop float = null,
	@tinhtrang_sudung nvarchar(1) = NULL,
	@tinhtrang_uv nvarchar(1) = NULL
)
AS
BEGIN

	SELECT @makhuvuc = department FROM trtb_m_op WHERE c_op = @macongdoan
	IF @makhuvuc IS NULL
		SET @makhuvuc = 'SON'

	INSERT INTO tr_dinhmuc_son3
	(
		id,
		masp,
		stt,
		buoc,
		mact,
		tenct,
		soluong,
		matson,
		t_sort,
		ngaytao,
		nguoitao,
		ngaysua,
		nguoisua,
		makhuvuc,
		macongdoan,
		stt_buoc,
		donhot,
		thoigiankho,
		cachthuchien,
		tonghonhop,
		tinhtrang_sudung,
		tinhtrang_uv
	)
	VALUES
	(
		@id,
		@masp,
		@stt,
		@buoc,
		LTRIM(RTRIM(@mact)),
		@tenct,
		@soluong,
		@matson,
		@t_sort,
		@ngaytao,
		@nguoitao,
		@ngaysua,
		@nguoisua,
		@makhuvuc,
		@macongdoan,
		@stt_buoc,
		@donhot,
		@thoigiankho,
		@cachthuchien,
		@tonghonhop,
		@tinhtrang_sudung,
		@tinhtrang_uv
	)
END","parseAnalysis":{"readsTables":["dbo.trtb_m_op"],"writesTables":["dbo.tr_dinhmuc_son3"],"flags":[],"suggestedTier":"B"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
